css:
@import url('https://cdn.jsdelivr.net/gh/orioncactus/pretendard@v1.3.9/dist/web/variable/pretendardvariable-dynamic-subset.min.css');
@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;700&display=swap');

/* ====================================================================
   Theme tokens — warm cream + burnt accent
==================================================================== */
:root {
    --bg: #faf9f5;
    --surface: #ffffff;
    --text: #1f1e1d;
    --text-mute: #6b6a65;
    --text-dim: #a09e96;
    --border: #ebe8de;
    --border-strong: #d6d2c4;
    --accent: #c96442;
    --accent-hover: #a95234;
    --accent-soft: #f4e3d8;
    --code-bg: #f2efe5;
    --code-text: #1f1e1d;
    --inline-code-bg: #ece9dd;
    --selection-bg: #f4d7bd;
    --selection-text: #1f1e1d;

    --font-sans: 'Pretendard Variable', Pretendard, -apple-system, BlinkMacSystemFont, system-ui, 'Apple SD Gothic Neo', 'Noto Sans KR', 'Segoe UI', sans-serif;
    --font-mono: 'JetBrains Mono', 'D2Coding', 'Fira Code', ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;

    --container: 1040px;
    --container-narrow: 720px;
    --radius: 8px;
    --radius-lg: 12px;
    --shadow-sm: 0 1px 0 rgba(31, 30, 29, 0.04);
    --transition: 160ms ease;
}

[data-theme='dark'] {
    --bg: #1f1e1d;
    --surface: #262624;
    --text: #f0efe7;
    --text-mute: #b5b2a8;
    --text-dim: #7a776e;
    --border: #38362f;
    --border-strong: #4a4742;
    --accent: #d67050;
    --accent-hover: #e58866;
    --accent-soft: #3a2a22;
    --code-bg: #2a2826;
    --code-text: #f0efe7;
    --inline-code-bg: #353330;
    --selection-bg: #4a3329;
    --selection-text: #f4d7bd;
}

@media (prefers-color-scheme: dark) {
    :root:not([data-theme='light']) {
        --bg: #1f1e1d;
        --surface: #262624;
        --text: #f0efe7;
        --text-mute: #b5b2a8;
        --text-dim: #7a776e;
        --border: #38362f;
        --border-strong: #4a4742;
        --accent: #d67050;
        --accent-hover: #e58866;
        --accent-soft: #3a2a22;
        --code-bg: #2a2826;
        --code-text: #f0efe7;
        --inline-code-bg: #353330;
        --selection-bg: #4a3329;
        --selection-text: #f4d7bd;
    }
}

/* ====================================================================
   Reset & base
==================================================================== */
*, *::before, *::after { box-sizing: border-box; }

html {
    -webkit-text-size-adjust: 100%;
    text-size-adjust: 100%;
    scroll-behavior: smooth;
}

body {
    margin: 0;
    font-family: var(--font-sans);
    font-size: 16px;
    line-height: 1.7;
    color: var(--text);
    background: var(--bg);
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    text-rendering: optimizeLegibility;
    font-feature-settings: 'kern', 'liga', 'calt';
    word-break: keep-all;
    overflow-wrap: anywhere;
    transition: background-color var(--transition), color var(--transition);
}

::selection {
    background: var(--selection-bg);
    color: var(--selection-text);
}

img, video {
    max-width: 100%;
    height: auto;
    display: block;
}

a {
    color: inherit;
    text-decoration: none;
}

button {
    font: inherit;
    color: inherit;
    background: none;
    border: 0;
    cursor: pointer;
    padding: 0;
}

input, textarea {
    font: inherit;
    color: inherit;
}

hr {
    border: 0;
    border-top: 1px solid var(--border);
    margin: 3rem 0;
}

.skip-link {
    position: absolute;
    left: -9999px;
    top: 0;
    padding: 8px 12px;
    background: var(--text);
    color: var(--bg);
    z-index: 100;
}
.skip-link:focus { left: 12px; top: 12px; }

/* ====================================================================
   Layout
==================================================================== */
.container {
    max-width: var(--container);
    margin: 0 auto;
    padding: 0 24px;
}

.main { padding: 56px 0 96px; }

@media (max-width: 640px) {
    .container { padding: 0 20px; }
    .main { padding: 32px 0 64px; }
}

/* ====================================================================
   Header
==================================================================== */
.site-header {
    position: sticky;
    top: 0;
    z-index: 10;
    background: color-mix(in srgb, var(--bg) 88%, transparent);
    backdrop-filter: saturate(180%) blur(12px);
    -webkit-backdrop-filter: saturate(180%) blur(12px);
    border-bottom: 1px solid transparent;
    transition: border-color var(--transition);
}

.header-inner {
    display: flex;
    align-items: center;
    gap: 24px;
    height: 64px;
}

.header-social {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    align-items: center;
    gap: 4px;
}
.header-social-link {
    width: 32px;
    height: 32px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 999px;
    color: var(--text-mute);
    transition: background var(--transition), color var(--transition);
}
.header-social-link:hover {
    background: var(--inline-code-bg);
    color: var(--text);
}

.nav {
    display: flex;
    gap: 20px;
    margin-left: auto;
    align-items: center;
}
.nav ul {
    display: flex;
    gap: 20px;
    list-style: none;
    margin: 0;
    padding: 0;
    align-items: center;
}
.nav ul li { margin: 0; padding: 0; }

.nav-link,
.nav ul a {
    font-size: 14px;
    color: var(--text-mute);
    text-decoration: none;
    transition: color var(--transition);
}
.nav-link:hover,
.nav ul a:hover { color: var(--text); }

.header-tools {
    display: flex;
    align-items: center;
    gap: 12px;
}

.search input {
    width: 140px;
    height: 32px;
    padding: 0 12px;
    border: 1px solid var(--border);
    border-radius: 999px;
    background: transparent;
    font-size: 13px;
    color: var(--text);
    transition: border-color var(--transition), width var(--transition);
}
.search input::placeholder { color: var(--text-dim); }
.search input:focus {
    outline: none;
    border-color: var(--border-strong);
    width: 180px;
}

.theme-toggle {
    width: 32px;
    height: 32px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 999px;
    color: var(--text-mute);
    transition: background var(--transition), color var(--transition);
}
.theme-toggle:hover {
    background: var(--inline-code-bg);
    color: var(--text);
}

.theme-icon { display: none; }
[data-theme='light'] .icon-moon { display: block; }
[data-theme='dark'] .icon-sun { display: block; }

@media (max-width: 640px) {
    .header-inner { gap: 12px; height: 56px; }
    .nav { gap: 14px; }
    .nav-link:nth-child(n+3) { display: none; }
    .search { display: none; }
}

/* ====================================================================
   Hero (index) — projects rail
==================================================================== */
.hero {
    padding: 8px 0 28px;
    margin-bottom: 32px;
    border-bottom: 1px solid var(--border);
}

@media (max-width: 640px) {
    .hero { padding: 4px 0 20px; margin-bottom: 24px; }
}

.hero-projects {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 10px;
}
.hero-projects-label {
    font-size: 11px;
    font-weight: 600;
    color: var(--text-dim);
    text-transform: uppercase;
    letter-spacing: 0.1em;
}
.project-tag {
    display: inline-flex;
    align-items: center;
    padding: 7px 14px;
    font-size: 13.5px;
    font-weight: 600;
    color: var(--accent);
    background: var(--accent-soft);
    border: 1px solid transparent;
    border-radius: 999px;
    text-decoration: none;
    transition: color var(--transition), background var(--transition);
}
.project-tag:hover {
    color: var(--bg);
    background: var(--accent);
}

/* ====================================================================
   Category chips (index quick nav)
==================================================================== */
.category-nav {
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
    margin-bottom: 48px;
    padding-bottom: 24px;
    border-bottom: 1px solid var(--border);
    overflow-x: auto;
    scrollbar-width: none;
    -ms-overflow-style: none;
}
.category-nav::-webkit-scrollbar { display: none; }

.category-chip {
    flex-shrink: 0;
    display: inline-flex;
    align-items: center;
    padding: 7px 14px;
    font-size: 13.5px;
    font-weight: 500;
    color: var(--text-mute);
    background: transparent;
    border: 1px solid transparent;
    border-radius: 999px;
    letter-spacing: -0.005em;
    transition: color var(--transition), background var(--transition), border-color var(--transition);
}
.category-chip:hover {
    color: var(--text);
    background: var(--inline-code-bg);
}
.category-chip.is-active {
    color: var(--bg);
    background: var(--text);
}
.category-chip.is-active:hover {
    background: var(--text);
    opacity: 0.9;
}
.category-chip--more {
    color: var(--accent);
    margin-left: auto;
}
.category-chip--more:hover {
    color: var(--accent-hover);
    background: var(--accent-soft);
}

.category-list-auto ul,
.category-list-auto li {
    list-style: none;
    margin: 0;
    padding: 0;
    display: contents;
}
.category-list-auto a {
    flex-shrink: 0;
    display: inline-flex;
    align-items: center;
    padding: 7px 14px;
    font-size: 13.5px;
    font-weight: 500;
    color: var(--text-mute);
    background: transparent;
    border: 1px solid transparent;
    border-radius: 999px;
    text-decoration: none;
    letter-spacing: -0.005em;
    transition: color var(--transition), background var(--transition);
}
.category-list-auto a:hover {
    color: var(--text);
    background: var(--inline-code-bg);
}
.category-list-auto .link_tit {
    color: var(--bg);
    background: var(--text);
}
.category-list-auto .link_tit:hover {
    background: var(--text);
    opacity: 0.9;
}

.category-list-auto img,
.category-list-auto .ico_new,
.category-list-auto .tt_ico_new,
.category-list-auto .txt_new,
.category-list-auto .new,
.category-list-auto i,
.post-list img,
.post-list .ico_new,
.post-list .tt_ico_new,
.post-list .txt_new,
.post-list .new,
.post-list i,
.post-title img,
.post-title .ico_new,
.post-title .tt_ico_new,
.post-title .txt_new,
.post-title .new,
img[src*="new_ico"],
img[src*="new.gif"],
img[src*="icon_new"],
img[alt="new" i],
img[alt="N" i] {
    display: none !important;
}

@media (max-width: 640px) {
    .category-nav {
        margin-bottom: 32px;
        padding-bottom: 16px;
        flex-wrap: nowrap;
        margin-left: -20px;
        margin-right: -20px;
        padding-left: 20px;
        padding-right: 20px;
    }
    .category-chip--more { margin-left: 4px; }
}

.page-head {
    padding: 24px 0 40px;
    border-bottom: 1px solid var(--border);
    margin-bottom: 40px;
}

.page-title {
    margin: 0;
    font-size: clamp(24px, 3.4vw, 32px);
    font-weight: 700;
    letter-spacing: -0.02em;
    line-height: 1.25;
}
.page-title em {
    font-style: normal;
    color: var(--accent);
}

.featured-section {
    margin-bottom: 64px;
}

.featured-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 20px;
}

.featured-card {
    display: flex;
    flex-direction: column;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    overflow: hidden;
    color: var(--text);
    transition: transform var(--transition), border-color var(--transition), box-shadow var(--transition);
    will-change: transform;
}
.featured-card:hover {
    border-color: var(--border-strong);
    transform: translateY(-2px);
    box-shadow: 0 6px 16px rgba(31, 30, 29, 0.06);
}
[data-theme='dark'] .featured-card:hover {
    box-shadow: 0 6px 16px rgba(0, 0, 0, 0.35);
}

.featured-thumb {
    aspect-ratio: 16 / 10;
    background: var(--inline-code-bg);
    overflow: hidden;
}
.featured-thumb img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 320ms ease;
}
.featured-card:hover .featured-thumb img {
    transform: scale(1.03);
}

.featured-body {
    padding: 18px 20px 22px;
    display: flex;
    flex-direction: column;
    gap: 6px;
}

.featured-category {
    font-size: 11.5px;
    font-weight: 600;
    color: var(--accent);
    letter-spacing: 0.06em;
    text-transform: uppercase;
}

.featured-title {
    margin: 2px 0 0;
    font-size: 17px;
    font-weight: 700;
    line-height: 1.4;
    letter-spacing: -0.012em;
    color: var(--text);
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.featured-summary {
    margin: 4px 0 0;
    font-size: 13.5px;
    line-height: 1.6;
    color: var(--text-mute);
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

@media (max-width: 640px) {
    .featured-section { margin-bottom: 40px; }
    .featured-grid { grid-template-columns: 1fr; gap: 16px; }
    .featured-thumb { aspect-ratio: 16 / 9; }
    .featured-body { padding: 16px 18px 20px; }
}

.section-title {
    margin: 0 0 20px;
    font-size: 12px;
    font-weight: 600;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    color: var(--text-dim);
}
.section-title-count {
    margin-left: 8px;
    color: var(--text-dim);
    font-weight: 500;
}

.post-list-section { margin-bottom: 64px; }

.post-list {
    list-style: none;
    margin: 0;
    padding: 0;
}

.post-item + .post-item { border-top: 1px solid var(--border); }

.post-link {
    display: grid;
    grid-template-columns: auto auto auto 1fr auto;
    align-items: baseline;
    gap: 14px;
    padding: 18px 0;
    transition: padding var(--transition);
}
.post-link:hover { padding-left: 4px; }

.post-thumb,
.post-summary { display: none; }

.post-date {
    font-size: 13px;
    font-variant-numeric: tabular-nums;
    color: var(--text-dim);
    white-space: nowrap;
}

.post-meta-divider { color: var(--text-dim); }

.post-category {
    font-size: 12px;
    font-weight: 500;
    color: var(--text-mute);
    text-transform: uppercase;
    letter-spacing: 0.04em;
    white-space: nowrap;
}

.post-title {
    margin: 0;
    font-size: 16px;
    font-weight: 500;
    line-height: 1.45;
    color: var(--text);
    letter-spacing: -0.005em;
}

.post-arrow {
    color: var(--text-dim);
    font-size: 14px;
    opacity: 0;
    transform: translateX(-4px);
    transition: opacity var(--transition), transform var(--transition);
}
.post-link:hover .post-arrow {
    opacity: 1;
    transform: translateX(0);
    color: var(--accent);
}

@media (max-width: 640px) {
    .post-link {
        grid-template-columns: auto auto 1fr;
        grid-template-rows: auto auto;
        gap: 4px 10px;
        padding: 16px 0;
    }
    .post-title { grid-column: 1 / -1; font-size: 15px; }
    .post-arrow { display: none; }
}

body#tt-body-index .post-list {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 20px;
    row-gap: 0;
}
body#tt-body-index .post-item:nth-child(-n+2) {
    border-top: 0;
}
body#tt-body-index .post-item:nth-child(n+3) {
    grid-column: 1 / -1;
}
body#tt-body-index .post-item:nth-child(3) {
    margin-top: 36px;
}

body#tt-body-index .post-item:nth-child(-n+2) .post-link {
    display: flex;
    flex-direction: column;
    align-items: stretch;
    gap: 0;
    padding: 0;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    overflow: hidden;
    transition: transform var(--transition), border-color var(--transition), box-shadow var(--transition);
}
body#tt-body-index .post-item:nth-child(-n+2) .post-link:hover {
    padding: 0;
    border-color: var(--border-strong);
    transform: translateY(-2px);
    box-shadow: 0 6px 16px rgba(31, 30, 29, 0.06);
}
[data-theme='dark'] body#tt-body-index .post-item:nth-child(-n+2) .post-link:hover {
    box-shadow: 0 6px 16px rgba(0, 0, 0, 0.35);
}

body#tt-body-index .post-item:nth-child(-n+2) .post-thumb {
    display: block;
    width: 100%;
    aspect-ratio: 1200 / 630;
    padding: 0;
    background-color: #f0ede5;
    background-size: contain;
    background-position: center;
    background-repeat: no-repeat;
}
body#tt-body-index .post-item:nth-child(-n+2) .post-thumb.post-thumb--empty {
    background-color: var(--surface);
    background-image: none;
}

body#tt-body-index .post-item:nth-child(-n+2) .post-date,
body#tt-body-index .post-item:nth-child(-n+2) .post-meta-divider,
body#tt-body-index .post-item:nth-child(-n+2) .post-arrow {
    display: none;
}

body#tt-body-index .post-item:nth-child(-n+2) .post-category {
    margin: 18px 20px 0;
    font-size: 11.5px;
    font-weight: 600;
    color: var(--accent);
    letter-spacing: 0.06em;
    text-transform: uppercase;
}

body#tt-body-index .post-item:nth-child(-n+2) .post-title {
    margin: 4px 20px 0;
    font-size: 17px;
    font-weight: 700;
    line-height: 1.25;
    letter-spacing: -0.012em;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

body#tt-body-index .post-item:nth-child(-n+2) .post-summary {
    display: -webkit-box;
    margin: 0 20px 22px;
    font-size: 13.5px;
    line-height: 1.6;
    color: var(--text-mute);
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

@media (max-width: 640px) {
    body#tt-body-index .post-list { grid-template-columns: 1fr; gap: 16px; }
    body#tt-body-index .post-item:nth-child(-n+2) .post-thumb { aspect-ratio: 1200 / 630; }
    body#tt-body-index .post-item:nth-child(3) { margin-top: 24px; }
}

.post {
    padding-top: 8px;
    max-width: var(--container-narrow);
    margin: 0 auto;
}

.post-header {
    padding: 16px 0 32px;
    border-bottom: 1px solid var(--border);
    margin-bottom: 40px;
}

.post-meta {
    margin: 0 0 16px;
    font-size: 13px;
    color: var(--text-dim);
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
}
.post-meta-category {
    color: var(--text-mute);
    font-weight: 500;
    text-transform: uppercase;
    letter-spacing: 0.06em;
}

.post-h1 {
    margin: 0;
    font-size: clamp(26px, 3.6vw, 36px);
    font-weight: 700;
    line-height: 1.25;
    letter-spacing: -0.02em;
    color: var(--text);
}

.post-header:has(+ .post-body .post-subtitle) {
    padding-bottom: 12px;
    border-bottom: 0;
    margin-bottom: 0;
}

.post-body .post-subtitle {
    margin: 0 0 28px;
    padding-bottom: 28px;
    border-bottom: 1px solid var(--border);
    font-size: 1.05rem;
    line-height: 1.55;
    font-weight: 400;
    color: var(--text-mute);
    letter-spacing: -0.005em;
}

.post-body {
    font-size: 16px;
    line-height: 1.8;
    color: var(--text);
}

.post-body > * + * { margin-top: 1.25em; }

.post-body h1, .post-body h2, .post-body h3, .post-body h4 {
    line-height: 1.35;
    letter-spacing: -0.015em;
    font-weight: 700;
    color: var(--text);
}

.post-body h1 { margin-top: 2.4em; font-size: 1.7em; }
.post-body h2 {
    margin-top: 2.2em;
    font-size: 1.4em;
    padding-top: 0.4em;
    border-top: 1px solid var(--border);
}
.post-body h3 { margin-top: 1.8em; font-size: 1.2em; }
.post-body h4 { margin-top: 1.6em; font-size: 1.05em; }

.post-body p { margin: 0; }

.post-body a {
    color: var(--accent);
    text-decoration: underline;
    text-decoration-thickness: 1px;
    text-underline-offset: 3px;
    text-decoration-color: color-mix(in srgb, var(--accent) 40%, transparent);
    transition: text-decoration-color var(--transition), color var(--transition);
}
.post-body a:hover {
    color: var(--accent-hover);
    text-decoration-color: var(--accent-hover);
}

.post-body blockquote {
    margin: 1.5em 0;
    padding: 4px 0 4px 20px;
    border-left: 3px solid var(--border-strong);
    color: var(--text-mute);
    font-style: normal;
}
.post-body blockquote p + p { margin-top: 0.6em; }

.post-body ul, .post-body ol {
    padding-left: 1.4em;
    margin: 0;
}
.post-body li + li { margin-top: 0.4em; }
.post-body li > ul, .post-body li > ol { margin-top: 0.4em; }

.post-body img {
    margin: 1.5em auto;
    border-radius: var(--radius);
}
.post-body figure {
    margin: 1.5em 0;
}
.post-body figcaption {
    margin-top: 0.6em;
    font-size: 13px;
    color: var(--text-dim);
    text-align: center;
}

.post-body table {
    width: 100%;
    border-collapse: collapse;
    font-size: 14px;
    margin: 1.5em 0;
}
.post-body th, .post-body td {
    padding: 10px 12px;
    border-bottom: 1px solid var(--border);
    text-align: left;
}
.post-body th {
    font-weight: 600;
    color: var(--text-mute);
    border-bottom-color: var(--border-strong);
}

.post-body code,
.post-body kbd,
.post-body samp {
    font-family: var(--font-mono);
    font-size: 0.88em;
    font-feature-settings: 'liga' 0;
}

.post-body :not(pre) > code {
    padding: 2px 6px;
    background: var(--inline-code-bg);
    border-radius: 4px;
    color: var(--text);
    white-space: nowrap;
}

.post-body pre {
    position: relative;
    margin: 1.6em 0;
    padding: 18px 20px;
    background: var(--code-bg);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    overflow-x: auto;
    font-size: 13.5px;
    line-height: 1.65;
    color: var(--code-text);
    -webkit-overflow-scrolling: touch;
}

.post-body pre code {
    background: transparent;
    padding: 0;
    border-radius: 0;
    color: inherit;
    white-space: pre;
    font-size: inherit;
}

.post-body pre::-webkit-scrollbar { height: 8px; }
.post-body pre::-webkit-scrollbar-track { background: transparent; }
.post-body pre::-webkit-scrollbar-thumb {
    background: var(--border-strong);
    border-radius: 999px;
}

.code-copy {
    position: absolute;
    top: 10px;
    right: 10px;
    padding: 4px 10px;
    font-size: 11px;
    font-weight: 500;
    letter-spacing: 0.04em;
    color: var(--text-dim);
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 999px;
    opacity: 0;
    transition: opacity var(--transition), color var(--transition), border-color var(--transition);
}
.post-body pre:hover .code-copy,
.code-copy:focus { opacity: 1; }
.code-copy:hover {
    color: var(--text);
    border-color: var(--border-strong);
}

.post-footer {
    margin-top: 56px;
    padding-top: 24px;
    border-top: 1px solid var(--border);
}

.post-tags { display: flex; flex-wrap: wrap; gap: 8px; }

.post-tags a,
.post-tags .tag {
    display: inline-block;
    padding: 4px 10px;
    font-size: 12px;
    color: var(--text-mute);
    background: var(--inline-code-bg);
    border-radius: 999px;
    transition: color var(--transition), background var(--transition);
}
.post-tags a:hover {
    color: var(--text);
    background: var(--border);
}

.tag-cloud {
    display: flex;
    flex-wrap: wrap;
    gap: 8px 10px;
    padding: 16px 0;
}

.tag-cloud-item {
    display: inline-flex;
    align-items: baseline;
    gap: 6px;
    padding: 6px 12px;
    border: 1px solid var(--border);
    border-radius: 999px;
    font-size: 13px;
    color: var(--text-mute);
    transition: color var(--transition), border-color var(--transition), background var(--transition);
}
.tag-cloud-item:hover {
    color: var(--text);
    border-color: var(--border-strong);
    background: var(--inline-code-bg);
}
.tag-cloud-name { font-weight: 500; }
.tag-cloud-count {
    font-size: 11px;
    color: var(--text-dim);
    font-variant-numeric: tabular-nums;
}

.paging {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 16px;
    margin-top: 64px;
    padding-top: 24px;
    border-top: 1px solid var(--border);
}

.paging-nums {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    gap: 4px;
}
.paging-nums a {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 32px;
    height: 32px;
    padding: 0 8px;
    font-size: 13px;
    color: var(--text-mute);
    border-radius: 6px;
    font-variant-numeric: tabular-nums;
    transition: background var(--transition), color var(--transition);
}
.paging-nums a:hover {
    color: var(--text);
    background: var(--inline-code-bg);
}
.paging-nums a.selected,
.paging-nums a.current {
    color: var(--bg);
    background: var(--text);
}

.paging-link {
    font-size: 13px;
    color: var(--text-mute);
    transition: color var(--transition);
}
.paging-link:hover { color: var(--text); }

.comments {
    margin-top: 80px;
    padding-top: 32px;
    border-top: 1px solid var(--border);
}

.comment-list {
    list-style: none;
    margin: 0 0 32px;
    padding: 0;
}

.comment {
    padding: 16px 0;
    border-bottom: 1px solid var(--border);
}
.comment:last-child { border-bottom: 0; }

.comment-head {
    display: flex;
    align-items: baseline;
    gap: 10px;
    margin-bottom: 6px;
}
.comment-author { font-size: 14px; font-weight: 600; color: var(--text); }
.comment-date { font-size: 12px; color: var(--text-dim); }

.comment-body {
    font-size: 14.5px;
    line-height: 1.7;
    color: var(--text);
}
.comment-body p { margin: 0; }

.comment-tools { margin-top: 6px; font-size: 12px; color: var(--text-dim); }
.comment-tools a { color: var(--text-mute); margin-right: 8px; }
.comment-tools a:hover { color: var(--text); }

.comment-form { margin-top: 20px; }
.comment-form input[type="text"],
.comment-form input[type="email"],
.comment-form input[type="url"],
.comment-form textarea {
    width: 100%;
    padding: 10px 12px;
    margin-bottom: 8px;
    border: 1px solid var(--border);
    border-radius: var(--radius);
    background: var(--surface);
    color: var(--text);
    font-size: 14px;
    transition: border-color var(--transition);
}
.comment-form textarea { min-height: 120px; resize: vertical; }
.comment-form input:focus,
.comment-form textarea:focus {
    outline: none;
    border-color: var(--text);
}
.comment-form button,
.comment-form input[type="submit"] {
    padding: 8px 16px;
    background: var(--text);
    color: var(--bg);
    border-radius: var(--radius);
    font-size: 13px;
    font-weight: 500;
    cursor: pointer;
    transition: opacity var(--transition);
}
.comment-form button:hover { opacity: 0.85; }

.sidebar {
    margin-top: 96px;
    padding-top: 32px;
    border-top: 1px solid var(--border);
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
    gap: 24px;
}
.sidebar-module {
    font-size: 13px;
    color: var(--text-mute);
}
.sidebar-module h3,
.sidebar-module h4 {
    margin: 0 0 10px;
    font-size: 12px;
    font-weight: 600;
    letter-spacing: 0.14em;
    text-transform: uppercase;
    color: var(--text-dim);
}
.sidebar-module ul {
    list-style: none;
    padding: 0;
    margin: 0;
}
.sidebar-module li { padding: 4px 0; }
.sidebar-module a { color: var(--text); transition: color var(--transition); }
.sidebar-module a:hover { color: var(--accent); }

.site-footer {
    border-top: 1px solid var(--border);
    padding: 32px 0;
    margin-top: 64px;
}
.footer-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: 12px;
    font-size: 12px;
    color: var(--text-dim);
}
.footer-copy { margin: 0; }
.footer-meta { margin: 0; display: flex; gap: 8px; align-items: center; }
.footer-meta a {
    color: var(--text-mute);
    transition: color var(--transition);
}
.footer-meta a:hover { color: var(--text); }

body:not(#tt-body-index) .index-only { display: none !important; }

body#tt-body-index .page-head { display: none; }

@media print {
    .site-header, .site-footer, .paging, .comments, .theme-toggle, .search, .code-copy { display: none; }
    body { background: white; color: black; }
    .post-body pre { border: 1px solid #ddd; background: #fafafa; }
}
